<style scoped>
.section-single-course {
    padding: 8% 0;
}

.single-course-block {
    gap: 60px;
}

.course-title,
.course-detail,
.course-questions {
    display: flex;
    flex-direction: column;
    gap: 20px;
}

.course-content {
    display: flex;
    flex-direction: column;
    gap: 30px;
    width: 55%;
}

.course-title h2,
.course-detail h2,
.course-questions h2 {
    font-family: var(--font-montserrat);
    font-weight: 300;
    line-height: normal;
    letter-spacing: 2%;
    color: var(--primary-100);
}

.course-title h2 {
    font-size: 42px;
}

.course-detail h2,
.course-questions h2 {
    font-size: 32px;
}

.course-title p,
.course-detail span {
    font-family: var(--font-inter);
    font-weight: 300;
    font-size: 18px;
    line-height: normal;
    letter-spacing: 0%;
    color: var(--primary-60);
    width: 100%;
}

.course-detail h2 {
    font-size: 32px;
}

.course-img {
    width: 100%;
    height: 423px;
    border-radius: 16px;
    overflow: hidden;
    position: relative;
}

.course-img:before {
    content: "";
    background: var(--single-course-item);
    width: 100%;
    height: 100%;
    position: absolute;
}

.course-img img {
    width: 100%;
    height: 100%;
    object-fit: cover;
}

.course-detail svg path {
    fill: var(--secondary-1-100);
}

.checkmark-section {
    display: flex;
    flex-direction: column;
    gap: 20px;
}

.course-questions {
    width: 100%;
}

.question-content svg {
    margin-right: 20px;
}

.question,
.question-bg-active {
    width: 100%;
    padding: 18px;
    border-radius: 16px;
    border-width: .5px;
    border-style: solid;
    border-color: var(--primary-50);
    -webkit-appearance: none !important;
    box-sizing: border-box !important;
    outline: none !important;
    transform: scale(1) !important;
}

.question-bg-active {
    background-image: url("/assets/images/home/online-course.png");
    outline: none !important;
    border: none;
    background-position: center;
    background-size: cover;
    position: relative;
    overflow: hidden;
}

.question-bg-active:before {
    content: "";
    width: 100%;
    height: 100%;
    position: absolute;
    top: 0;
    left: 0;
    background: var(--single-course-question);
}

.question-bg-active .span {
    color: var(--white-245);
}

.question-bg-active svg path {
